declare @q nvarchar(4000), @message nvarchar(4000), @field varchar(32), @user int, @admin bit, @year int, @r int select @admin = @@admin, @user = @@userID, @year = nam_bd from dmstt
-- Checking &Checking;
select @field = 'ma_dvcs' if @admin <> 1 begin if @type = '1' and @@sysDatabaseName.dbo.FastBusiness$System$GetAuthorize(@admin, @user, 'SFCShopOpeningBalance', 'Edit') = 0 select @type = '0'
select @r = min(a.stt) from @@table a where not exists(select 1 from cdpx b where a.ma_vt = b.ma_vt and a.ma_dvcs = b.ma_dvcs and a.ma_px = b.ma_px and a.ma_lsx = b.ma_lsx and a.ma_cd = b.ma_cd and a.ma_lo = b.ma_lo and a.loai = b.loai and b.nam = @year) and not exists(select 1 from sysunitrights c where a.ma_dvcs = c.ma_dvcs and user_id = @user and r_new = 1) &Error;
if @type = '1' select @r = min(a.stt) from @@table a where exists(select 1 from cdpx b where a.ma_vt = b.ma_vt and a.ma_dvcs = b.ma_dvcs and a.ma_px = b.ma_px and a.ma_lsx = b.ma_lsx and a.ma_cd = b.ma_cd and a.ma_lo = b.ma_lo and a.loai = b.loai and b.nam = @year) and not exists(select 1 from sysunitrights c where a.ma_dvcs = c.ma_dvcs and user_id = @user and r_edit = 1) &Error; end
if @type = '0' delete @@table from @@table a where exists(select 1 from cdpx b where a.ma_vt = b.ma_vt and a.ma_dvcs = b.ma_dvcs and a.ma_px = b.ma_px and a.ma_lsx = b.ma_lsx and a.ma_cd = b.ma_cd and a.loai = b.loai and a.ma_lo = b.ma_lo and b.nam = @year) select @r = min(a.stt) from @@table a join dmkho b on a.ma_dvcs = b.ma_dvcs join dmdvcsks c on b.ma_dvcs = c.ma_dvcs where year(c.ngay_ks) >= @year&Error;
select a.* into #k from @@table a join cdpx b on a.ma_vt = b.ma_vt and a.ma_dvcs = b.ma_dvcs and a.ma_px = b.ma_px and a.ma_lsx = b.ma_lsx and a.ma_cd = b.ma_cd and a.loai = b.loai and a.ma_lo = b.ma_lo and b.nam = @year delete @@table from @@table a where exists(select 1 from #k b where a.ma_vt = b.ma_vt and a.ma_dvcs = b.ma_dvcs and a.ma_px = b.ma_px and a.ma_lsx = b.ma_lsx and a.ma_cd = b.ma_cd and a.loai = b.loai and a.ma_lo = b.ma_lo)
--insert &Inserting;
if @type = '1' &Updating; where a.nam = @year
